arguments.file_text:
@* Popup with common reaction emojis *@

<div class="emoji-picker">
    @foreach (var emoji in _emojis)
    {
        <button class="emoji-option" @onclick="() => SelectEmoji(emoji)" title="@emoji">
            @emoji
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "🔥"];

    private async Task SelectEmoji(string emoji)
    {
        await OnEmojiSelected.InvokeAsync(emoji);
    }
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background: var(--bs-body-bg, #fff);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 8px;
    padding: 4px 6px;
    box-shadow: 0 2px 8px rgba(0,0,0,.15);
    position: absolute;
    bottom: 100%;
    right: 0;
    z-index: 10;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    padding: 4px 6px;
    border-radius: 4px;
    cursor: pointer;
    line-height: 1;
}

.emoji-option:hover {
    background: var(--bs-tertiary-bg, #f0f0f0);
}

@* Reusable message input: textarea + send/reply button *@

<div class="message-input-area">
    <textarea class="form-control message-textarea"
              placeholder="@Placeholder"
              @bind="Text"
              @onkeydown="HandleKeyDown"
              rows="2"></textarea>
    <button class="btn btn-primary send-btn" @onclick="Submit" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter, EditorRequired] public EventCallback<string> OnSubmit { get; set; }

    private string Text { get; set; } = "";

    private async Task Submit()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var content = Text.Trim();
        Text = "";
        await OnSubmit.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Submit();
        }
    }
}

.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid var(--bs-border-color, #dee2e6);
    background: var(--bs-body-bg, #fff);
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    resize: none;
    border-radius: 8px;
    font-size: 0.9rem;
}

.send-btn {
    flex-shrink: 0;
    border-radius: 8px;
    padding: 6px 16px;
    align-self: flex-end;
}

