@* Renders a single chat message with reactions, hover actions, and thread link *@

<div class="chat-message @(IsHighlighted ? "highlighted" : "")" @onmouseenter="ShowActions" @onmouseleave="HideActions">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time" title="@Message.SentAt.ToString("f")">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="thread-link" @onclick="() => OnThreadClicked.InvokeAsync(Message.Id)">
            @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)" title="Reply in thread">
                💬
            </button>
            <div class="react-wrapper">
                <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                    😊
                </button>
                @if (_showEmojiPicker)
                {
                    <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter] public bool IsHighlighted { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<int> OnThreadClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void ShowActions() => _showActions = true;

    private void HideActions()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        _showActions = false;
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

