@* Left sidebar showing the list of channels *@

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h6 class="sidebar-title">Channels</h6>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <button class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                    @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name-row">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="badge bg-primary unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                @if (!string.IsNullOrWhiteSpace(channel.Description))
                {
                    <span class="channel-desc">@Truncate(channel.Description, 40)</span>
                }
            </button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int maxLength)
        => text.Length <= maxLength ? text : text[..maxLength] + "…";
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: var(--bs-dark-bg-subtle, #2b2d31);
    color: var(--bs-body-color, #313338);
    border-right: 1px solid var(--bs-border-color, #dee2e6);
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid var(--bs-border-color, #dee2e6);
}

.sidebar-title {
    margin: 0;
    font-weight: 700;
    text-transform: uppercase;
    font-size: 0.75rem;
    letter-spacing: 0.05em;
    color: var(--bs-secondary-color, #6c757d);
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
}

.channel-item {
    display: block;
    width: 100%;
    text-align: left;
    background: none;
    border: none;
    border-radius: 6px;
    padding: 8px 10px;
    margin-bottom: 2px;
    cursor: pointer;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background: rgba(var(--bs-primary-rgb, 13,110,253), 0.08);
}

.channel-item.active {
    background: rgba(var(--bs-primary-rgb, 13,110,253), 0.15);
    font-weight: 600;
}

.channel-name-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-size: 0.9rem;
    font-weight: 500;
}

.channel-item.active .channel-name {
    font-weight: 700;
}

.unread-badge {
    font-size: 0.7rem;
    padding: 2px 6px;
    border-radius: 10px;
}

.channel-desc {
    display: block;
    font-size: 0.75rem;
    color: var(--bs-secondary-color, #6c757d);
    margin-top: 2px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

