toolArgs.file_text:
@* Main message area: channel header, scrollable messages, input *@

<div class="message-area">
    <div class="message-area-header">
        <h5 class="mb-0"># @Channel.Name</h5>
        <span class="text-muted small">@Channel.Description</span>
    </div>

    <div class="message-list" @onscroll="HandleScroll" @ref="_messageListRef">
        @if (IsLoadingMore)
        {
            <div class="text-center py-2">
                <div class="spinner-border spinner-border-sm text-secondary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }

        @foreach (var message in Messages)
        {
            <ChatMessage Message="message"
                         ThreadSummary="GetThreadSummary(message.Id)"
                         IsHighlighted="message.Id == HighlightedMessageId"
                         OnReplyClicked="OnReplyClicked"
                         OnThreadClicked="OnThreadClicked"
                         OnReactionAdded="OnReactionAdded" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                  ButtonLabel="Send"
                  OnSubmit="OnMessageSent" />
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public int? HighlightedMessageId { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<string> OnMessageSent { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<int> OnThreadClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;

    private ThreadSummary? GetThreadSummary(int messageId)
        => ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);

    private async Task HandleScroll()
    {
        // Scroll-to-top detection is handled via JS interop in the page
        // For simplicity, we expose the callback and let the parent decide
        await OnLoadMore.InvokeAsync();
    }
}

