@* Right panel: thread view with root message, replies, and reply input *@

<div class="thread-panel">
    <div class="thread-header">
        <h6 class="mb-0">Thread</h6>
        <button class="btn-close btn-close-sm" @onclick="OnClose" aria-label="Close thread"></button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="thread-root-author">@RootMessage.Author</div>
            <div class="thread-root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span class="thread-divider-text">@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="message-header">
                        <span class="message-author">@reply.Author</span>
                        <span class="message-time" title="@reply.SentAt.ToString("f")">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply…"
                      ButtonLabel="Reply"
                      OnSubmit="OnReplySent" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReplySent { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    border-left: 1px solid var(--bs-border-color, #dee2e6);
    background: var(--bs-body-bg, #fff);
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid var(--bs-border-color, #dee2e6);
    flex-shrink: 0;
