arguments.file_text:
@page "/chat"
@rendermode InteractiveServer
@using sv_ea37d7346fd54b86ac1314b1188ac30b.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(_threadOpen ? "" : "chat-main-expanded")">
        @if (_activeChannel is not null)
        {
            <MessageArea Channel="_activeChannel"
                         Messages="_messages"
                         ThreadSummaries="_threadSummaries"
                         HighlightedMessageId="_threadRootMessageId"
                         IsLoadingMore="_isLoadingMore"
                         OnMessageSent="SendMessage"
                         OnReplyClicked="OpenThread"
                         OnThreadClicked="OpenThread"
                         OnReactionAdded="AddReaction"
                         OnLoadMore="LoadMoreMessages" />
        }
        else
        {
            <div class="d-flex align-items-center justify-content-center h-100 text-muted">
                <span>Select a channel to start chatting</span>
            </div>
        }
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnReplySent="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int _activeChannelId;
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private List<ThreadSummary> _threadSummaries = [];
    private bool _isLoadingMore;

    // Thread state
    private bool _threadOpen;
    private int? _threadRootMessageId;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    // Pagination
    private const int PageSize = 30;
    private int _skip;
    private bool _allLoaded;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _skip = 0;
        _allLoaded = false;

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _skip = _messages.Count;

        BuildThreadSummaries();
        CloseThread();

        await ChatService.MarkChannelReadAsync(channelId);

        // Update the local unread count
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = _channels[idx];
            _channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore || _allLoaded || _activeChannel is null) return;

        _isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId, _skip, PageSize);
        if (older.Count < PageSize) _allLoaded = true;

        _messages.InsertRange(0, older);
        _skip += older.Count;
        _isLoadingMore = false;

        BuildThreadSummaries();
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannel is null) return;

        var msg = await ChatService.SendMessageAsync(_activeChannelId, content, null);
        _messages.Add(msg);
        _skip++;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the local message
        var idx = _messages.FindIndex(m => m.Id == args.MessageId);
        if (idx >= 0)
        {
            var msg = _messages[idx];
            var existingReaction = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existingReaction is not null)
            {
                if (!existingReaction.Users.Contains("You"))
                    existingReaction.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessageId = rootMessageId;
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessageId = null;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessageId is null || _activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId, content, _threadRootMessageId);
        _threadReplies.Add(reply);

        // Update thread summary
        BuildThreadSummaries();
    }

    private void BuildThreadSummaries()
    {
        // Build summaries from messages that have replies referencing them
        var replyGroups = _messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value);

        _threadSummaries = replyGroups.Select(g => new ThreadSummary(
            g.Key,
            g.Count(),
            g.Max(m => m.SentAt)
        )).ToList();
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
}

.chat-main-expanded {
    flex: 1;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

